const { expect } = require('chai');
const QualifierProcessor = require('../../../../../src/lib/processors/inject/QualifierProcessor');

describe('@Qualifier Processor', () => {
  it('should register and inject qualified instance during DI stage', () => {
    class MyService {}

    class Consumer {
      constructor() {
        this.myService = null;
      }
    }

    const instance = new Consumer();

    // Mock DI Container
    const registered = new Map();
    const ctx = {
      instance,
      container: {
        // Resolver gibt exakt die registrierte Instanz zurück
        resolveByQualifier(name) {
          return registered.get(name);
        },
        registerQualifier(name, obj) {
          registered.set(name, obj);
        }
      },
      log: []
    };

    // Vorher registrierte Instanz im Container
    const serviceInstance = new MyService();
    ctx.container.registerQualifier('MyService', serviceInstance);

    const meta = {
      args: ['MyService'],
      propertyName: 'myService',
      instance, // ⚡ Das ist die Consumer-Instanz
      className: 'Consumer'
    };

    // Prozess-DI aufrufen
    QualifierProcessor.processDI(meta, ctx);

    // Assertions
    expect(instance.myService).to.equal(serviceInstance); // ← exakt die registrierte Instanz
    expect(ctx.log).to.include('@Qualifier injected: myService ← MyService');
  });
});
